                        "Gemini usage initial sync",
                        crate::services::session_usage_gemini::sync_gemini_usage(db),
                    );
                    run_step(
                        "OpenCode usage initial sync",
                        crate::services::session_usage_opencode::sync_opencode_usage(db),
